package ir.tahamohamadi.blog.tag; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="tag") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class Tag extends AuditedSoftDeletableEntity { @Column(name="tag_key",nullable=false,length=100) private String tagKey; @Column(name="is_active",nullable=false) private boolean active; private Tag(UUID id,String key,Instant at){initialize(id,at);tagKey=requireNonBlank(key,"tagKey");active=true;} public static Tag create(UUID id,String key,Instant at){return new Tag(id,key,at);} public void rename(String key){tagKey=requireNonBlank(key,"tagKey");updatedAt=Instant.now();} public void deactivate(){active=false;updatedAt=Instant.now();} }
